class Solution:
    def survivedRobotsHealths(self, positions, healths, directions):
        n = len(positions)
        robots = list(range(n))
        hp = healths[:]
        alive = [True] * n

        def spatial_order():
            return sorted([i for i in robots if alive[i]], key=lambda i: positions[i])

        changed = True
        while changed:
            changed = False
            order = spatial_order()
            for a, b in zip(order, order[1:]):
                if directions[a] == 'R' and directions[b] == 'L':
                    if hp[a] < hp[b]:
                        alive[a] = False
                        hp[b] -= 1
                    elif hp[a] > hp[b]:
                        alive[b] = False
                        hp[a] -= 1
                    else:
                        alive[a] = False
                        alive[b] = False
                    changed = True
                    break
        return [hp[i] for i in range(n) if alive[i]]

