var survivedRobotsHealths = function(positions, healths, directions) {
    const n = positions.length;
    const order = Array.from({length: n}, (_, i) => i).sort((a, b) => positions[a] - positions[b]);
    const hp = healths.slice();
    const alive = new Array(n).fill(true);
    const stack = [];
    for (const idx of order) {
        if (directions[idx] === 'R') {
            stack.push(idx);
            continue;
        }
        while (stack.length > 0) {
            const top = stack[stack.length - 1];
            if (hp[top] < hp[idx]) {
                alive[top] = false;
                stack.pop();
                hp[idx] -= 1;
            } else if (hp[top] > hp[idx]) {
                hp[top] -= 1;
                alive[idx] = false;
                break;
            } else {
                alive[top] = false;
                alive[idx] = false;
                stack.pop();
                break;
            }
        }
    }
    const res = [];
    for (let i = 0; i < n; i++) if (alive[i]) res.push(hp[i]);
    return res;
};
